module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

wire [3:0] ext_mul_a;
wire [3:0] ext_mul_b;
assign ext_mul_a = {4{1'b0}} | mul_a;
assign ext_mul_b = {4{1'b0}} | mul_b;

genvar i;
generate
    for (i = 0; i < 4; i = i + 1) begin : gen_partial_products
        wire [3:0] pp;
        assign pp = (ext_mul_b[i]) ? (ext_mul_a << i) : 'd0;
    end
endgenerate

reg [7:0] sum_tmp1;
reg [7:0] sum_tmp2;
integer j;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum_tmp1 <= 8'd0;
        sum_tmp2 <= 8'd0;
    end else begin
        sum_tmp1 <= (ext_mul_b[0] ? ext_mul_a : 4'd0) + (ext_mul_b[1] ? ext_mul_a << 1 : 4'd0);
        sum_tmp2 <= (ext_mul_b[2] ? ext_mul_a << 2 : 4'd0) + (ext_mul_b[3] ? ext_mul_a << 3 : 4'd0);
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 8'd0;
    end else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end
endmodule
